const keyOf = (value) => JSON.stringify(value)

function bump(m, value, delta) {
  const k = keyOf(value)
  const existing = m.get(k)
  m.set(k, [value, (existing ? existing[1] : 0) + delta])
}

function consolidate(m) {
  for (const [k, [, count]] of m) if (count === 0) m.delete(k)
  return m
}

export class Collection {
  constructor(inner) {
    this.inner = inner
  }

  static empty() {
    return new Collection(new Map())
  }

  static fromArray(items) {
    const m = new Map()
    for (const x of items) bump(m, x, 1)
    return new Collection(consolidate(m))
  }

  static fromEntries(entries) {
    const m = new Map()
    for (const [value, mult] of entries) bump(m, value, mult)
    return new Collection(consolidate(m))
  }

  entries() {
    return [...this.inner.values()].filter(([, count]) => count !== 0)
  }

